mapper.insert:
INSERT INTO CHAT_ROOM (
	room_id, room_type, room_title, created_at, max_capacity
) VALUES (
	#{roomId}, #{roomType}, #{roomTitle}, SYSDATE, 2
)

INSERT INTO CHAT_ROOM_USER (
	seq, room_id, member_id, joined_at, last_read_at
) VALUES (
	SEQ_CHAT_ROOM_USER.NEXTVAL, #{roomId}, #{memberId}, SYSDATE, SYSTIMESTAMP
)

INSERT INTO MEMBER_BLOCK (
	block_seq, member_id, blocked_id, blocked_at
) VALUES (
	SEQ_MEMBER_BLOCK.NEXTVAL, #{memberId}, #{blockedId}, SYSDATE
)
